const body = $input.first().json.body;

return [{
  json: {
    tema: body.tema,
    tipoConteudo: body.tipoConteudo,
    formato: body.formato,
    persona: body.persona,
    perfilPersona: body.perfilPersona,
    campanha: body.campanha,
    referencias: body.referencias,
    message: `Criar post de Instagram sobre: ${body.tema}. Tipo: ${body.tipoConteudo}. Formato: ${body.formato}. Persona: ${body.persona} (${body.perfilPersona}). ${body.campanha ? 'Campanha: ' + body.campanha : ''}`
  }
}];
